// Function to mirror the binary tree
Node* treeMirrorSwap(Node* root) {
    // Base case: if the tree is empty, return nullptr
    if (root == nullptr)
        return nullptr;

    // Swap the left and right subtrees
    Node* swappedLeft = treeMirrorSwap(root->left);
    Node* swappedRight = treeMirrorSwap(root->right);

    // Update the left and right child pointers
    root->left = swappedRight;
    root->right = swappedLeft;

    // Return the root of the mirrored tree
    return root;
}

// Function to print the binary tree
void printTree(Node* root, int level = 0) {
    if (root != nullptr) {
        printTree(root->right, level + 1);
        for (int i = 0; i < level; i++)
            cout << "  ";
        cout << "Node " << root->value << std::endl;
        printTree(root->left, level + 1);
    }
}

