public class TreeProcessor {
    /**
     * Calculates the maximum depth of a binary tree.
     *
     * @param root The root node of the tree.
     * @return The maximum depth of the tree, or 0 if the tree is empty.
     */
    public static int calculateTreeDepth(TreeNode root) {
        // Base case: If the tree is empty, return 0
        if (root == null) {
            return 0;
        }

        // Recursively calculate the depth of the left and right subtrees
        int leftDepth = calculateTreeDepth(root.left);
        int rightDepth = calculateTreeDepth(root.right);

        // The maximum depth is the greater of the left and right subtrees plus 1
        return Math.max(leftDepth, rightDepth) + 1;
    }

