std::string normalizeURL(const std::string& url) {
    if (url.length() > 300) {
        return url;
    }

    size_t protocolEnd = url.find("://");
    if (protocolEnd != std::string::npos) {
        std::string protocol = url.substr(0, protocolEnd);
        std::transform(protocol.begin(), protocol.end(), protocol.begin(),
            [](unsigned char c){ return std::tolower(c); });
        url = protocol + url.substr(protocolEnd + 3);
    } else {
        url = "http://" + url;
    }

    size_t queryStart = url.find('?');
    if (queryStart != std::string::npos) {
        std::string query = url.substr(queryStart + 1);
        std::map<std::string, std::vector<std::string>> params;
        size_t paramStart = 0;
        while ((paramStart = query.find("&")) != std::string::npos) {
            std::string param = query.substr(0, paramStart);
            size_t equalPos = param.find("=");
            if (equalPos != std::string::npos) {
                std::string key = param.substr(0, equalPos);
                std::string value = param.substr(equalPos + 1);
                params[key].push_back(value);
            }
            query.erase(0, paramStart + 1);
        }
        if (!query.empty()) {
            size_t equalPos = query.find("=");
            if (equalPos != std::string::npos) {
                std::string key = query.substr(0, equalPos);
                std::string value = query.substr(equalPos + 1);
                params[key].push_back(value);
            }
        }
        std::vector<std::pair<std::string, std::string>> sortedParams;
        for (const auto& pair : params) {
            std::sort(pair.first.begin(), pair.first.end());
            for (const auto& value : pair.second) {
                sortedParams.emplace_back(pair.first, value);
            }
        }
        std::string sortedQuery;
        for (const auto& param : sortedParams) {
            if (!sortedQuery.empty()) {
                sortedQuery += "&";
            }
            sortedQuery += param.first + "=" + param.second;
        }
        url = url.substr(0, queryStart) + "?" + sortedQuery;
    }

    return url;
}

int main() {
    std::string url = "https://example.com/path?a=1&b=2&c=3";
    std::cout << normalizeURL(url) << std::endl;
    return 0;
}
