std::string formatPath(const std::string& path) {
    // Remove leading and trailing whitespace
    std::string trimmedPath = path;
    trimmedPath.erase(0, trimmedPath.find_first_not_of(" \t\r\n"));
    trimmedPath.erase(trimmedPath.find_last_not_of(" \t\r\n") + 1);

    // If the path is empty, return it immediately
    if (trimmedPath.empty()) {
        return trimmedPath;
    }

    // Convert backslashes to forward slashes
    std::replace(trimmedPath.begin(), trimmedPath.end(), '\\', '/');

    // Split the path into components
    std::vector<std::string> components;
    size_t pos = 0;
    while ((pos = trimmedPath.find('/')) != std::string::npos) {
        components.push_back(trimmedPath.substr(0, pos));
        trimmedPath.erase(0, pos + 1);
    }
    components.push_back(trimmedPath);

    // Filter out empty components
    trimmedPath.clear();
    for (const auto& component : components) {
        if (!component.empty()) {
            trimmedPath += '/' + component;
        }
    }

    // If the path is a network path, keep the leading slash
    if (trimmedPath[0] == '\\') {
        return trimmedPath;
    }

    return trimmedPath;
}
