    num_vertices: usize,
    num_edges: usize,
}

impl Graph {
    fn new() -> Self {
        Graph {
            vertices: HashMap::new(),
            num_vertices: 0,
            num_edges: 0,
        }
    }

    fn add_vertex(&mut self, vertex: i32) {
        if self.num_vertices >= 100 {
            panic!("Graph is full. Cannot add more vertices.");
        }
        self.vertices.insert(vertex, Vec::new());
        self.num_vertices += 1;
    }

    fn add_edge(&mut self, vertex1: i32, vertex2: i32, weight: i32) {
        if self.num_vertices < 100 || self.num_edges >= 200 {
            panic!("Graph is full. Cannot add more edges.");
        }
        if let Some(vertices) = self.vertices.get_mut(&vertex1) {
            vertices.push((vertex2, weight));
            self.num_edges += 1;
        }
        if let Some(vertices) = self.vertices.get_mut(&vertex2) {
            vertices.push((vertex1, weight));
            self.num_edges += 1;
        }
    }

    fn prune_edges(&mut self, threshold_weight: i32) -> Self {
        let mut new_vertices = HashMap::new();
        let mut new_edges = HashMap::new();
        for (vertex, edges) in self.vertices.iter() {
            new_vertices.insert(*vertex, Vec::new());
            for (neighbour, weight) in edges.iter() {
                if weight >= threshold_weight {
                    new_vertices.get_mut(vertex).unwrap().push((*neighbour, *weight));
                    new_edges.insert((*neighbour, *vertex), *weight);
                }
            }
        }
        Graph {
            vertices: new_vertices,
            num_vertices: self.num_vertices,
            num_edges: new_edges.len() as usize,
        }
    }
}

fn graph_edge_prune(graph: &mut Graph) -> Graph {
    graph.prune_edges(10)
