// Function to count leaf nodes in a binary tree
int countLeafNodes(TreeNode* root) {
    // Base case: If the tree is empty, return 0
    if (root == nullptr) {
        return 0;
    }

    // If the node has no children, it's a leaf node, so return 1
    if (root->left == nullptr && root->right == nullptr) {
        return 1;
    }

    // Recursively count leaf nodes in the left and right subtrees
    int leftLeafCount = countLeafNodes(root->left);
    int rightLeafCount = countLeafNodes(root->right);

    // Return the total count of leaf nodes
    return leftLeafCount + rightLeafCount;
}

