public class Main {
    public static String swapCharPairs(String s) {
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            if (i % 2 == 0) {
                if (i < s.length() - 1) {
                    result.append(s.charAt(i + 1));
                    result.append(s.charAt(i));
                } else {
                    result.append(s.charAt(i));
                }
            } else {
                if (i > 0) {
                    result.append(s.charAt(i - 1));
                    result.append(s.charAt(i));
                } else {
                    result.append(s.charAt(i));
                }
            }
        }
        return result.toString();
    }

    public static void main(String[] args) {
        System.out.println(swapCharPairs("abcdefg"));
        System.out.println(swapCharPairs("abcd"));
        System.out.println(swapCharPairs("abc"));
    }
}
