public class Main {
    public static boolean isPrime(int n) {
        if (n < 0 || n >= 1000) {
            throw new IllegalArgumentException("Input must be a non-negative integer less than 1000");
        }
        if (n <= 1) {
            return false;
        }
        for (int i = 2; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println(isPrime(11));  // true
        System.out.println(isPrime(15));  // false
        System.out.println(isPrime(1001)); // throws IllegalArgumentException
    }
