def get_even_numbers(numbers):
    if not all(1 <= num <= 100 for num in numbers):
        raise ValueError("All numbers must be within the inclusive range of 1 to 100")
    if len(numbers) != len(set(numbers)):
        raise ValueError("The input list must contain unique integers")

    return sorted([num for num in numbers if num % 2 == 0])

